  "name": "@devdashproject/devdash-cli",
  "version": "0.3.0",
  "description": "AI-powered task tracking CLI for developers and coding agents",
  "bin": {
    "devdash": "bin/devdash"
  },
  "scripts": {
    "postinstall": "node postinstall.js"
  },
  "optionalDependencies": {
    "@devdashproject/devdash-darwin-arm64": "0.3.0",
    "@devdashproject/devdash-darwin-x64": "0.3.0",
