    "type": "git",
    "url": "https://github.com/jasonmassey/devdash-cli-go"
  },
  "license": "MIT",
  "keywords": [
    "devdash",
    "task-tracking",
    "cli",
    "ai-agents",
    "developer-tools"
  ]
}

